/**
 * Share of the Pie — US economic data, 1947–2024.
 *
 * All dollar values are nominal (current-year) EXCEPT CBO fields which are
 * constant 2021 dollars (deflated by PCE price index). Do not mix CBO dollars
 * with other nominal fields in ratio calculations.
 *
 * medianHouseholdIncome uses Census family income for 1947–1966 (household
 * concept didn't exist) and Census household income for 1967–2024. There is a
 * ~10% downward break at 1967 when non-family households enter the denominator.
 *
 * workingAgeMedianEarnings is a weighted-average approximation of the combined
 * male+female full-time year-round median, adjusted ×0.97 to better approximate
 * the true combined median. Available 1966–2024 only.
 */

export type ShareOfPieYear = {
  year: number
  gdpPerCapita: number
  ndpPerCapita: number | null
  medianHouseholdIncome: number
  meanHouseholdIncome: number | null
  averageHouseholdSize: number
  meanPersonalIncomePerCapita: number | null
  workingAgeMedianEarnings: number | null
  workingAgeMedianEarningsMen: number | null
  workingAgeMedianEarningsWomen: number | null
  p20HouseholdIncome: number | null
  p80HouseholdIncome: number | null
  p95HouseholdIncome: number | null
  /** Constant 2021 dollars (PCE-deflated). */
  cboMarketIncomeMiddleQuintile: number | null
  /** Constant 2021 dollars (PCE-deflated). */
  cboAfterTaxIncomeMiddleQuintile: number | null
  employerHealthCostPerWorker: number | null
  benefitsShareOfCompensation: number | null
  effectiveFederalTaxRateMiddle: number | null
  laborForceParticipationWomen: number | null
  dualEarnerHouseholdShare: number | null
  workingAgePopulationShare: number | null
  blsLaborSharePercent: number | null
  isRecession: boolean
}

